import React, { useContext } from "react";
import { Routes, Route } from "react-router-dom"; // Import routing tools
import { GeneralContext } from "./GeneralContext";
import BuyActionWindow from "./BuyActionWindow";
import WatchList from "./WatchList";
import Orders from "./Orders";

// 1. Import your page components
import Summary from "./Summary";
import Holdings from "./Holdings";
import Positions from "./Positions";
import Funds from "./Funds";
import Apps from "./Apps"; 

const Dashboard = () => {
  const { isBuyWindowOpen, selectedStockUID } = useContext(GeneralContext);

  return (
    <div className="dashboard-container">
      <WatchList />

      <div className="content">
        {/* 2. Define the Routes for each page */}
        <Routes>
          <Route path="/" element={<Summary />} />
          <Route path="/holdings" element={<Holdings />} />
          <Route path="/positions" element={<Positions />} />
          <Route path="/funds" element={<Funds />} />
          <Route path="/apps" element={<Apps />} /> {/* <--- Add this route! */}
          <Route path="/orders" element={<Orders />} />
        </Routes>
      </div>

      {isBuyWindowOpen && <BuyActionWindow uid={selectedStockUID} />}
    </div>
  );
};

export default Dashboard;
